INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fc237481-a483-4809-bfa8-77e9b4e9bd2e',
  '00000000-0000-0000-0000-000000000001',
  $escape$Grafana Panel Selection — Matching Visualization to Data Shape and Audience$escape$,
  $escape$Grafana's panel picker is not a style choice — it's a semantic contract between your data and your audience. Reaching for Time series by default is the most common mistake. Use it only when temporal trends matter; for point-in-time values, a Stat panel with threshold-driven coloring communicates health faster than any line. When comparing discrete categories over time, State timeline beats Time series — it shows state transitions, not magnitude. Heatmaps are underused: if your histogram data is dense and you're watching latency percentiles shift, a Heatmap panel over a raw histogram reveals distribution drift that averages hide. For operational dashboards (NOC, oncall), maximize ink efficiency — Stat and Gauge panels with defined thresholds let someone read the board in under two seconds. For analytical dashboards (capacity planning, debugging), Table panels with field overrides and value mappings give engineers filterable, sortable raw signal. In Grafana 10+, the "Suggestions" tab in panel edit scores your active query's shape against panel types — treat it as a second opinion, not gospel. Schema drives the panel; the audience drives the layout.$escape$,
  $escape$// Panel JSON model excerpt — Stat panel with threshold config
{
  "type": "stat",
  "fieldConfig": {
    "defaults": {
      "thresholds": {
        "mode": "absolute",
        "steps": [
          { "color": "green", "value": null },
          { "color": "yellow", "value": 75 },
          { "color": "red", "value": 90 }
        ]
      },
      "mappings": [],
      "color": { "mode": "thresholds" }
    }
  },
  "options": {
    "reduceOptions": { "calcs": ["lastNotNull"] },
    "orientation": "auto",
    "colorMode": "background"
  }
}$escape$,
  $escape$javascript$escape$,
