INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f83d7b54-e6e6-4651-9edf-002a9da9391b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Grafana DE — Translating LookML Concepts into Grafana's Native Primitives$escape$,
  $escape$Looker's LookML semantic layer maps surprisingly cleanly onto Grafana's data model once you know where to look. An Explore in Looker is roughly equivalent to a Grafana data source + panel query scope — you define the join context once and reuse it. Dimensions and measures become Grafana's field overrides and value transformations: use the "Add field from calculation" transform to derive measures (e.g., ratio fields) directly in the panel pipeline rather than in SQL. Derived tables in LookML translate to Grafana's query-time transformations chained via the Transformations tab — group by, reduce, merge series — keeping your SQL clean. For embedding, Grafana exposes signed panel URLs via its HTTP API: POST to `/api/snapshots` for a read-only share or use the `auth_proxy` header for SSO-aware iframe embeds. Unlike Looker's embed secret flow, Grafana's `kiosk=tv` mode strips chrome entirely. One key difference: Grafana has no centralized semantic layer by default — use the Grafana Metrics Enterprise semantic layer plugin or define reusable queries via provisioned library panels to approximate LookML's single source of truth.$escape$,
  $escape$# Grafana HTTP API — create a signed snapshot for embedding
curl -X POST http://grafana:3000/api/snapshots \
  -H 'Content-Type: application/json' \
  -H 'Authorization: Bearer $GRAFANA_API_KEY' \
  -d '{
    "dashboard": { "id": 42, "panels": [] },
    "expires": 3600,
    "external": false
  }'
# Response: { "url": "http://grafana:3000/dashboard/snapshot/abc123", "key": "abc123" }
# Embed via: <iframe src="http://grafana:3000/d-solo/uid/slug?panelId=7&kiosk" />$escape$,
  $escape$bash$escape$,
