INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '50d2ba92-66fa-4ad5-992c-6b4e870818c4',
  '00000000-0000-0000-0000-000000000001',
  $escape$Grafana DE to Metabase — Questions, Models, and Signed Embedding Explained$escape$,
  $escape$For Grafana users, Metabase's mental model inverts your workflow. Where Grafana starts with a data source panel and PromQL/SQL, Metabase centers on Questions — either visual (GUI query builder) or native SQL. Questions compose into Dashboards just like Grafana panels, but without variable templating syntax like `${variable}` — Metabase uses filter widgets bound to dashboard parameters instead.

Models are Metabase's answer to Grafana's data source abstraction: curated, named SQL queries that act as virtual tables. Downstream questions query models, not raw tables — giving you a semantic layer without pulling in dbt.

Where Metabase genuinely beats Grafana: signed embedding. Grafana's iframe embedding exposes the full UI shell; Metabase generates a JWT-signed URL that sandboxes a single dashboard or question to a specific tenant. The payload encodes locked params for row-level filtering — end users never see schema details.

Admin setup mirrors Grafana's provisioning but is UI-driven: connect PostgreSQL under Admin → Databases, then set `METABASE_SECRET_KEY` as an environment variable. No YAML datasource files unlike Grafana's `/etc/grafana/provisioning/datasources/`.$escape$,
  $escape$import jwt from "jsonwebtoken";

const METABASE_SITE_URL = "https://metabase.yourdomain.com";
const METABASE_SECRET_KEY = process.env.METABASE_SECRET_KEY!;

function signedEmbedUrl(dashboardId: number, tenantId: string): string {
  const payload = {
    resource: { dashboard: dashboardId },
    params: { tenant_id: tenantId }, // locked row-level filter
    exp: Math.round(Date.now() / 1000) + 60 * 10,  // 10-min TTL
  };
  const token = jwt.sign(payload, METABASE_SECRET_KEY);
  return `${METABASE_SITE_URL}/embed/dashboard/${token}#bordered=true&titled=false`;
}$escape$,
  $escape$typescript$escape$,
