INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd56dc6a4-65f2-472e-a500-8d990163fc8b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Grafana Dashboard Design — Information Hierarchy That Actually Reduces Cognitive Load$escape$,
  $escape$Most Grafana dashboards fail not because of bad data but bad layout. Apply the F-pattern: top row should be collapsible Row panels housing 2–4 Stat panels showing your most critical KPIs — latency p99, error rate, active users. Below that, a Time series panel spanning full width gives temporal context. Detail panels live in collapsed rows that operators expand only when investigating.

Use field overrides, not panel duplication. One Time series panel with Display Name override `${__field.labels.service}` eliminates five near-identical panels. Set threshold-based color on Stat panels: green below baseline, yellow at warning, red at critical — your eyes parse color before text.

For storytelling, wire Annotations to your deployment events via the built-in Grafana annotations API. When a spike appears, the deployment marker is already there. Add Panel links pointing to drill-down dashboards using `${__data.fields.service}` as a URL variable — readers follow the narrative from summary to detail without context-switching. Target 12–16 panels max per dashboard; beyond that, split by audience role.$escape$,
  $escape$// Panel field override: color thresholds on a Stat panel (panel JSON excerpt)
"fieldConfig": {
  "defaults": {
    "thresholds": {
      "mode": "absolute",
      "steps": [
        { "color": "green", "value": null },
        { "color": "yellow", "value": 200 },
        { "color": "red",   "value": 500 }
      ]
    },
    "mappings": [],
    "links": [{
      "title": "Drill down → ${__field.name}",
      "url": "/d/service-detail?var-service=${__data.fields.service}"
    }]
  }
}$escape$,
  $escape$bash$escape$,
