INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '654bcdf4-aa7b-4476-9ed9-694cedec78ad',
  '00000000-0000-0000-0000-000000000001',
  $escape$Grafana — Controlling Data Freshness Without Hammering Your Data Source$escape$,
  $escape$Grafana's auto-refresh interval is a blunt instrument. Setting a dashboard to 5s refresh on a slow Prometheus or Loki source creates query storms and cascading timeouts. Use min_interval in each panel's query options to set a floor — Grafana won't fire a query more frequently than this value, even if the dashboard refresh is faster. For expensive queries, enable query caching at the data source level (Grafana Enterprise or OSS with the caching plugin): set a cache TTL that matches your acceptable lag SLA. A typical ops dashboard can tolerate 30s staleness; a billing dashboard cannot. Use Grafana's built-in $__interval variable to auto-align step resolution to the current time range, preventing over-fetching on zoomed-out views. For SLA enforcement, add a 'Last updated' stat panel using the datasource's native `time` field with the `last` reducer — this makes lag visible to users. On Grafana Cloud, configure Grafana-managed alerting with an evaluation interval tied to your data freshness SLA rather than defaulting to 1m blindly.$escape$,
  $escape$# grafana/provisioning/datasources/prometheus.yaml
apiVersion: 1
datasources:
  - name: Prometheus
    type: prometheus
    url: http://prometheus:9090
    jsonData:
      timeInterval: '15s'        # min_interval floor for all panels
      queryTimeout: '60s'
      cacheLevel: 'High'         # Enterprise: aggressive query caching
      incrementalQuerying: true  # reduces re-fetch on time range extend
    secureJsonData: {}$escape$,
  $escape$bash$escape$,
