INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '626b7554-87fd-4e50-a443-5400177dc122',
  '00000000-0000-0000-0000-000000000001',
  $escape$Grafana — Per-User Row-Level Security with JWT Embedding and Built-In User Variables$escape$,
  $escape$Grafana exposes `${__user.login}` and `${__user.email}` as built-in template variables that resolve server-side inside every panel query — this is your zero-cost RLS primitive without requiring Grafana Enterprise's paid feature.

The setup requires two parts. First, configure `auth.jwt` in `grafana.ini` pointing to your JWKS endpoint. Your backend signs a short-lived JWT containing the viewer's email and role claims, then appends `?auth_token=<jwt>` to the iframe `src`. Grafana decodes the token, maps or provisions the user session, and makes `${__user.email}` available in all downstream query contexts. Set `allow_embedding = true` and `cookie_samesite = none` for cross-origin iframe support.

Second, write your panel SQL filtering on that variable. Grafana interpolates it server-side before dispatching to the data source — the raw email never touches the client. The viewer cannot override it via URL params since it derives from the authenticated session, not a user-controlled variable.

Critical gotcha: `${__user.email}` returns an empty string for unauthenticated sessions. Protect against silent full-table returns by adding a `NULLIF('${__user.email}', '')` guard in your WHERE clause — this forces a zero-row result rather than leaking data on broken embed flows.$escape$,
  $escape$-- Grafana panel query: server-side RLS via built-in user context
SELECT
  $__timeGroupAlias(created_at, $__interval),
  SUM(revenue)  AS revenue,
  region
FROM orders
WHERE
  -- Grafana interpolates ${__user.email} from the JWT session, not URL params
  owner_email = NULLIF('${__user.email}', '')  -- guard: zero rows if unauthenticated
  AND $__timeFilter(created_at)
GROUP BY 1, region
ORDER BY 1$escape$,
  $escape$sql$escape$,
