INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '45bd41ac-7793-4d8f-9a10-eb428d478b96',
  '00000000-0000-0000-0000-000000000001',
  $escape$Grafana — Why Your Dashboards Are Slow and How Materialized Views Fix It$escape$,
  $escape$Grafana dashboards stall when panels fire live queries against raw tables on every refresh cycle. If your PostgreSQL datasource runs heavy GROUP BY aggregations over millions of rows per panel, the bottleneck is the live connection model — not Grafana itself.

Switch high-cardinality panels to materialized views. Create the view with date_trunc bucketing at the finest resolution your dashboard needs (usually minute or hour), then point the Grafana panel query at the view using $__timeFilter(bucket) with ORDER BY bucket. Always refresh with CONCURRENTLY to avoid table locks while dashboards are live.

For Prometheus-backed dashboards, the equivalent is Mimir or Thanos recording rules — they pre-compute expensive range queries like rate() into a new metric series, so Grafana fetches a cheap point-lookup instead of triggering a full range scan across the TSDB.

Do not use Grafana's built-in Transformations as a substitute for server-side aggregation. Transformations execute client-side after the raw query returns, so they reduce render time but not datasource load. Push aggregation down to the datasource layer.

Also cap returned rows per panel by appending LIMIT $__maxDataPoints to SQL queries — Grafana resolves this variable to the panel's pixel width, preventing over-fetching on wide time ranges.$escape$,
  $escape$-- SLOW: live aggregation on raw table, fires on every refresh
SELECT
  $__timeGroupAlias(created_at, $__interval),
  avg(response_time_ms) AS avg_response
FROM http_logs
WHERE $__timeFilter(created_at)
GROUP BY 1
ORDER BY 1;

-- FAST: pre-aggregated materialized view
CREATE MATERIALIZED VIEW mv_http_metrics AS
SELECT
  date_trunc('minute', created_at) AS bucket,
  avg(response_time_ms)            AS avg_response
FROM http_logs
GROUP BY 1;

-- Grafana panel query — hits the view instead
SELECT bucket AS time, avg_response
FROM mv_http_metrics
WHERE $__timeFilter(bucket)
ORDER BY bucket
LIMIT $__maxDataPoints;$escape$,
