INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '76363363-d8fb-4cd4-ba24-ca3a91554276',
  '00000000-0000-0000-0000-000000000001',
  $escape$Grafana Mobile Dashboards — What Actually Renders on Small Screens$escape$,
  $escape$Grafana uses a 24-column grid. On viewports below 768px, every panel is force-stacked to full width — your gridPos `w` value becomes irrelevant. Design for this, not against it.

Stat and Gauge panels are mobile-native: single values, color-coded backgrounds, no legend clutter. Time Series panels with more than 4 series collapse into unreadable noise — limit series via query or switch to a Stat with a `lastNotNull` reducer.

Keep panel titles under 20 characters; Grafana truncates without tooltip on mobile. Disable the variables toolbar for mobile-targeted dashboards by setting `hideControls: true` in your provisioning JSON. Avoid Repeat panels — each repetition spawns a full-width row, creating endless scroll.

For dashboards accessed via Grafana's iOS/Android app or a browser kiosk, append `?kiosk` to strip the top nav and reclaim 48px. Use `?from=now-1h&to=now` in embedded links so users land in a sensible time range without needing the time picker.

Prioritize Stat → Gauge → Bar Gauge for mobile. Push Table and Heatmap panels to desktop-only rows using row visibility tricks via dashboard JSON `collapsed: true`.$escape$,
  $escape$# Bulk-set all Time Series panels to Stat for a mobile dashboard clone
import requests, json

GRAFANA_URL = "http://localhost:3000"
API_KEY = "Bearer glsa_xxxx"
DASHBOARD_UID = "abc123"

headers = {"Authorization": API_KEY, "Content-Type": "application/json"}
dash = requests.get(f"{GRAFANA_URL}/api/dashboards/uid/{DASHBOARD_UID}", headers=headers).json()

for panel in dash["dashboard"]["panels"]:
    if panel["type"] == "timeseries":
        panel["type"] = "stat"
        panel["options"] = {"reduceOptions": {"calcs": ["lastNotNull"]}, "colorMode": "background"}

dash["dashboard"]["title"] += " (Mobile)"
dash["overwrite"] = False
requests.post(f"{GRAFANA_URL}/api/dashboards/db", headers=headers, data=json.dumps(dash))$escape$,
  $escape$python$escape$,
