INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '09d28699-0965-4ebe-aa55-25b4dfa08b19',
  '00000000-0000-0000-0000-000000000001',
  $escape$Grafana Embedding — SSO, White-Labeling, and iFrame vs Scenes SDK$escape$,
  $escape$Grafana supports two embedding paths: iFrame and the `@grafana/scenes` SDK. iFrame is simpler but leaks Grafana branding unless you enable `[white_labeling]` in `grafana.ini` and set `app_title`, `login_logo`, and `fav_icon`. For SSO, enable `[auth.jwt]` with `url_login = true` — Grafana will extract the Bearer token from the `auth_token` query param, letting you mint short-lived JWTs server-side and inject them into the iFrame src. The downside: iFrames can't react to host-app state changes without postMessage gymnastics.

The Scenes SDK (`@grafana/scenes`) is the idiomatic escape hatch. You compose `EmbeddedScene`, `SceneFlexLayout`, and `VizPanel` directly in React — no iFrame, full TypeScript types, and direct access to Grafana's variable interpolation engine. Auth still flows through Grafana's backend (`/api/datasources/proxy`), but the renderer lives in your bundle. White-labeling becomes irrelevant since you own the chrome. Use iFrame when you need zero-JS simplicity; use Scenes when the dashboard must feel native to your product.$escape$,
  $escape$import { EmbeddedScene, SceneFlexLayout, SceneFlexItem, VizPanel, SceneTimeRange } from '@grafana/scenes';

export function buildCpuScene() {
  return new EmbeddedScene({
    $timeRange: new SceneTimeRange({ from: 'now-1h', to: 'now' }),
    body: new SceneFlexLayout({
      children: [
        new SceneFlexItem({
          body: new VizPanel({
            pluginId: 'timeseries',
            title: 'CPU Usage',
            datasource: { uid: 'prometheus-uid' },
            fieldConfig: { defaults: { unit: 'percent' }, overrides: [] },
          }),
        }),
      ],
    }),
  });
}$escape$,
  $escape$typescript$escape$,
