INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6f2fae1c-7833-44d1-9697-3541d7e83e21',
  '00000000-0000-0000-0000-000000000001',
  $escape$Grafana + Cube Metrics Layer — One Definition, Every Dashboard$escape$,
  $escape$When revenue or DAU is computed differently across five Grafana dashboards, you have a trust problem, not a tooling problem. A metrics layer — Cube or dbt Semantic Layer — centralizes those definitions and exposes them via a Postgres-compatible SQL API that Grafana can query directly.

Cube runs a SQL proxy on port 15432. Point Grafana's PostgreSQL datasource at it, and every panel query becomes a SELECT against a pre-defined measure instead of raw SQL guesswork. The measure's filters, joins, and time granularities are owned by the data team in version-controlled YAML — Grafana just renders.

In your panel, use Cube's time dimension syntax: `time_dimension` with `granularity` maps cleanly to Grafana's `$__timeGroup` macro equivalent. For dbt Semantic Layer, the JDBC endpoint (`semantic-layer.cloud.getdbt.com:443`) plugs into the same PostgreSQL datasource with SSL enabled.

This pattern eliminates dashboard-level metric drift. When a definition changes in Cube, every Grafana panel reflecting that measure updates without a single JSON edit.$escape$,
  $escape$# grafana/provisioning/datasources/cube.yaml
apiVersion: 1
datasources:
  - name: Cube Metrics Layer
    type: postgres
    url: localhost:15432
    database: db
    user: ${CUBE_SQL_USER}
    secureJsonData:
      password: ${CUBE_SQL_PASSWORD}
    jsonData:
      sslmode: disable
      timescaledb: false

-- Panel query: orders revenue by day
SELECT
  orders__created_at_day AS time,
  SUM(orders__revenue)   AS revenue
FROM orders
WHERE $__timeFilter(orders__created_at_day)
GROUP BY 1
ORDER BY 1$escape$,
  $escape$sql$escape$,
