INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '930cc760-e9ab-45f9-b2cb-dd194e6957ca',
  '00000000-0000-0000-0000-000000000001',
  $escape$Grafana — When to Use It vs Tableau, Looker, Metabase, and Superset$escape$,
  $escape$Grafana owns the observability layer: if your data lives in Prometheus, Loki, Tempo, or InfluxDB, nothing else competes. Its mixed-datasource panels let you correlate HTTP error rates (PromQL) with log spikes (LogQL) in a single view — no other tool on this list supports that natively.

Reach for Metabase when non-engineers need GUI-driven SQL exploration. Grafana's query UX assumes PromQL or LogQL fluency; Metabase doesn't.

Reach for Looker when your org needs a governed semantic layer. LookML defines `revenue` once; every Grafana dashboard redeclares its own aggregation independently — a maintenance trap at scale.

Reach for Superset for ad-hoc SQL exploration against ClickHouse or Druid. Superset's column-level filtering and SQL Lab outperform Grafana's plugin ecosystem for OLAP-style slicing.

Reach for Tableau when stakeholders need cross-tab pivot analysis or complex multi-join calculated fields. Grafana's Transformations panel can do basic joins but degrades past two sources.

Default rule: Grafana for operational and infrastructure data with time-series semantics. Delegate to BI tools the moment your audience shifts from engineers to business stakeholders querying relational or dimensional models.$escape$,
  $escape$// Grafana mixed-datasource panel target config (panel JSON)
// This is Grafana's unique edge — correlate metrics + logs in one panel
{
  "datasource": { "type": "mixed", "uid": "-- Mixed --" },
  "targets": [
    {
      "datasource": { "type": "prometheus", "uid": "${prometheus_uid}" },
      "expr": "rate(http_requests_total{status=~'5..'}[5m])",
      "legendFormat": "Error rate"
    },
    {
      "datasource": { "type": "loki", "uid": "${loki_uid}" },
      "expr": "{app=\"api\"} |= \"exception\" | logfmt | level=\"error\"",
      "legendFormat": "Error logs"
    }
  ]
}$escape$,
  $escape$javascript$escape$,
